import"./hoisted.DJU19TIk.js";document.getElementById("k-skicka")?.addEventListener("click",async()=>{const e=document.getElementById("k-skicka"),t=document.getElementById("k-namn")?.value.trim(),n=document.getElementById("k-telefon")?.value.trim(),d=document.getElementById("k-epost")?.value.trim(),o=document.getElementById("k-meddelande")?.value.trim(),c=document.getElementById("k-typ")?.value,i=document.getElementById("k-gaster")?.value.trim(),s=document.getElementById("k-datum")?.value,m=document.getElementById("k-hittade")?.value,k=document.getElementById("k-website")?.value;if(!t||!n||!d||!o){alert("Fyll i namn, telefon, e-post och ditt behov innan du skickar.");return}e.disabled=!0,e.textContent="Skickar…";try{const a=await fetch("/.netlify/functions/skicka-kontakt",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({namn:t,telefon:n,epost:d,meddelande:o,typ:c,gaster:i,datum:s,hittade:m,honeypot:k})}),l=await a.json();a.ok&&l.ok?window.location.href="/tack/":(alert(l.error||"Något gick fel, försök igen eller ring 072-448 10 00."),e.disabled=!1,e.textContent="Skicka meddelande")}catch{alert("Nätverksfel — försök igen eller ring 072-448 10 00."),e.disabled=!1,e.textContent="Skicka meddelande"}});
